import base64

def _decode(data, w, h):
    raw = base64.b64decode(data)
    rows = []
    for y in range(h):
        row = []
        for x in range(w):
            off = (y * w + x) * 4
            r, g, b, a = raw[off], raw[off+1], raw[off+2], raw[off+3]
            row.append((r, g, b) if a > 64 else None)
        rows.append(row)
    return rows

def _decode_entry(e):
    return _decode(e["data"], e["w"], e["h"])


